void test_real_world_blog_post(void) {
    /* Blog post with headings, paragraphs, code blocks, and links converts to readable Markdown */
    const char *html =
        "<article><h1>Getting Started with Rust</h1><p>Rust is a systems programming language "
        "focused on <strong>safety</strong>, <em>performance</em>, and concurrency. It was created "
        "by <a href=\"https://www.mozilla.org\">Mozilla</a> and has grown significantly in "
        "popularity.</p><h2>Installation</h2><p>Install Rust using the official "
        "installer:</p><pre><code class=\"language-bash\">curl --proto '=https' --tlsv1.2 -sSf "
        "https://sh.rustup.rs | sh</code></pre><h2>Hello World</h2><p>Create your first Rust "
        "program:</p><pre><code class=\"language-rust\">fn main() {\n    println!(\"Hello, "
        "world!\");\n}</code></pre><p>Run it with <code>cargo run</code> from your project "
        "directory.</p><h2>Key Concepts</h2><ul><li>Ownership and "
        "borrowing</li><li>Lifetimes</li><li>Traits and generics</li><li>Pattern "
        "matching</li></ul><p>For more information, visit the <a "
        "href=\"https://doc.rust-lang.org/book/\">Rust Book</a>.</p></article>";
    char *result = html_to_markdown_convert(html, NULL);
    assert(result != NULL && "conversion should succeed");

    /* content_not_empty */
    assert(strlen(result) > 0);
    /* content_contains_all */
    assert(strstr(result, "# Getting Started with Rust") != NULL);
    assert(strstr(result, "## Installation") != NULL);
    assert(strstr(result, "## Hello World") != NULL);
    assert(strstr(result, "## Key Concepts") != NULL);
    assert(strstr(result, "cargo run") != NULL);
    assert(strstr(result, "[Mozilla](https://www.mozilla.org)") != NULL);
    assert(strstr(result, "- Ownership and borrowing") != NULL);
    /* min_content_length */
    assert(strlen(result) >= 200);
    html_to_markdown_free_string(result);
}

